      </head>
      <body>
        <h1>Confirmation de commande</h1>
        <div class="order-info">
          <p><strong>N° commande :</strong> ${orderDetails.id}</p>
          <p><strong>Date :</strong> ${new Date(orderDetails.date).toLocaleDateString('fr-FR')}</p>
          <p><strong>Client :</strong> ${orderDetails.customerName}</p>
        </div>
        <table>
          <tr><th>Produit</th><th>Quantité</th><th>Prix unitaire</th><th>Total</th></tr>
          ${orderDetails.items.map(item => `
            <tr>
              <td>${item.name}</td>
              <td>${item.quantity}</td>
              <td>${item.price} €</td>
              <td>${item.quantity * item.price} €</td>
            </tr>
          `).join('')}
