import { useNavigation, CommonActions } from '@react-navigation/native';

function SuccessScreen({ route }) {
  const navigation = useNavigation();
  const { orderId } = route.params;

  const goToOrders = () => {
    // Réinitialiser la pile pour éviter de revenir au paiement
    navigation.dispatch(
      CommonActions.reset({
        index: 0,
        routes: [
          { name: 'MainTabs', params: { screen: 'Orders' } },
        ],
      })
    );
  };

  // Alternative : navigation.navigate avec replace
  const goToOrdersV2 = () => {
    navigation.replace('MainTabs', {
      screen: 'Orders',
      params: { highlightedOrder: orderId }
    });
  };

  return (
    <View>
      <Text>Commande #{orderId} confirmée !</Text>
      <Button title="Voir mes commandes" onPress={goToOrders} />
    </View>
  );
}
