import { useEffect } from 'react';
import { View, Text, StyleSheet } from 'react-native';
import Animated, { 
  useSharedValue, 
  useAnimatedStyle, 
  withTiming, 
  runOnJS 
} from 'react-native-reanimated';
import LottieView from 'lottie-react-native';

export default function TransitionScreen({ orderDetails, onFinish }) {
  const opacity = useSharedValue(1);
  const scale = useSharedValue(1);

  const animatedStyle = useAnimatedStyle(() => ({
    opacity: opacity.value,
    transform: [{ scale: scale.value }],
  }));

  useEffect(() => {
    const timer = setTimeout(() => {
      // Démarrer l'animation de sortie
      opacity.value = withTiming(0, { duration: 500 });
      scale.value = withTiming(0.8, { duration: 500 }, () => {
        runOnJS(onFinish)();
      });
    }, 2000);

    return () => clearTimeout(timer);
  }, []);

  return (
    <View style={styles.container}>
      <Animated.View style={[styles.card, animatedStyle]}>
        <LottieView
          source={require('../assets/success.json')}
          style={styles.animation}
          autoPlay
          loop={false}
        />
        <Text style={styles.title}>Commande confirmée !</Text>
        <Text style={styles.subtitle}>N° {orderDetails.id}</Text>
        <Text style={styles.amount}>{orderDetails.total} €</Text>
      </Animated.View>
    </View>
  );
}

const styles = StyleSheet.create({
  container: { flex: 1, justifyContent: 'center', alignItems: 'center', backgroundColor: '#4CAF50' },
