import { Linking } from 'react-native';

const shareToWhatsApp = async (orderDetails, phoneNumber = null) => {
  const message = `✅ *Commande confirmée !*\n\n` +
    `📦 N° commande : ${orderDetails.id}\n` +
    `📅 Date : ${new Date(orderDetails.date).toLocaleDateString('fr-FR')}\n` +
