import AsyncStorage from '@react-native-async-storage/async-storage';

const ORDERS_STORAGE_KEY = '@user_orders';

// Sauvegarder une nouvelle commande
const saveOrderConfirmation = async (orderDetails) => {
  try {
    // Récupérer l'historique existant
    const existingOrders = await getOrdersHistory();

    // Ajouter la nouvelle commande
    const newOrder = {
      ...orderDetails,
      timestamp: Date.now(),
    };

    const updatedOrders = [newOrder, ...existingOrders];

    // Sauvegarder (limiter à 50 commandes maximum)
    const ordersToSave = updatedOrders.slice(0, 50);
    await AsyncStorage.setItem(ORDERS_STORAGE_KEY, JSON.stringify(ordersToSave));

    return true;
  } catch (error) {
    console.error('Erreur lors de la sauvegarde:', error);
    return false;
  }
};

// Récupérer l'historique des commandes
const getOrdersHistory = async () => {
  try {
    const ordersJson = await AsyncStorage.getItem(ORDERS_STORAGE_KEY);
    return ordersJson ? JSON.parse(ordersJson) : [];
  } catch (error) {
    console.error('Erreur lors de la récupération:', error);
    return [];
  }
};

// Récupérer une commande spécifique
const getOrderById = async (orderId) => {
  const orders = await getOrdersHistory();
  return orders.find(order => order.id === orderId);
};

// Supprimer l'historique (déconnexion)
const clearOrdersHistory = async () => {
  try {
    await AsyncStorage.removeItem(ORDERS_STORAGE_KEY);
  } catch (error) {
    console.error('Erreur lors du nettoyage:', error);
  }
};
