import * as Notifications from 'expo-notifications';
import { Platform } from 'react-native';

// Configurer le handler d'affichage des notifications
Notifications.setNotificationHandler({
  handleNotification: async () => ({
    shouldShowAlert: true,
    shouldPlaySound: true,
    shouldSetBadge: true,
  }),
});

const sendLocalConfirmationNotification = async (orderDetails) => {
  // Demander les permissions
  const { status } = await Notifications.getPermissionsAsync();
  if (status !== 'granted') {
    const { status: newStatus } = await Notifications.requestPermissionsAsync();
    if (newStatus !== 'granted') {
      console.log('Permissions de notification refusées');
      return;
    }
  }

  // Planifier la notification (immédiate)
  await Notifications.scheduleNotificationAsync({
    content: {
      title: '✅ Commande confirmée !',
      body: `Votre commande n°${orderDetails.id} a été validée. Total : ${orderDetails.total} €`,
      data: { orderId: orderDetails.id, screen: 'OrderDetails' },
      sound: true,
      badge: 1,
      ...(Platform.OS === 'android' && {
        channelId: 'order-confirmations',
      }),
    },
    trigger: null, // Notification immédiate
  });
};

// Créer un canal de notification pour Android
const createNotificationChannel = async () => {
  if (Platform.OS === 'android') {
    await Notifications.setNotificationChannelAsync('order-confirmations', {
      name: 'Confirmations de commande',
      importance: Notifications.AndroidImportance.HIGH,
      vibrationPattern: [0, 250, 250, 250],
      lightColor: '#4CAF50',
    });
  }
};

// Appeler createNotificationChannel dans App.js au démarrage
