import QRCode from 'react-native-qrcode-svg';
import { View, Text, Button, StyleSheet, Alert } from 'react-native';
import * as Sharing from 'expo-sharing';
import { captureRef } from 'react-native-view-shot';
import { useRef } from 'react';

export default function OrderQRCode({ orderDetails }) {
  const qrCodeRef = useRef();

  const qrData = JSON.stringify({
    orderId: orderDetails.id,
    date: orderDetails.date,
    total: orderDetails.total,
    customer: orderDetails.customerName,
  });

  const shareQRCode = async () => {
    try {
      const uri = await captureRef(qrCodeRef, {
        format: 'png',
        quality: 1,
      });

      if (await Sharing.isAvailableAsync()) {
        await Sharing.shareAsync(uri, {
          mimeType: 'image/png',
          dialogTitle: 'Partager le QR code',
        });
      }
    } catch (error) {
      Alert.alert('Erreur', 'Impossible de partager le QR code');
    }
  };

  return (
    <View style={styles.container}>
      <Text style={styles.title}>QR code de retrait</Text>
      <View ref={qrCodeRef} collapsable={false} style={styles.qrContainer}>
        <QRCode
          value={qrData}
          size={200}
          backgroundColor="white"
          color="black"
        />
      </View>
      <Text style={styles.orderId}>Commande #{orderDetails.id}</Text>
      <Button title="Partager le QR code" onPress={shareQRCode} />
    </View>
  );
}

const styles = StyleSheet.create({
  container: { alignItems: 'center', padding: 20 },
  title: { fontSize: 18, fontWeight: 'bold', marginBottom: 15 },
  qrContainer: { padding: 15, backgroundColor: 'white', borderRadius: 10 },
  orderId: { marginTop: 15, fontSize: 14, color: '#666' },
});
